function resetExpense(){expenseForm.reset();expenseEditId.value='';expenseFormTitle.textContent='Cost / receipt';expenseDate.value=todayISO();pendingAttachment.expense=null;showAttachment('expense');cancelExpenseEdit.classList.add('hidden')}
async function fileData(file){if(!file)return null;if(file.size>4_000_000)throw new Error('File too large');if(!ALLOWED_ATTACHMENT_TYPES.has(file.type))throw new Error('Unsupported file type');return new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>{const a=safeAttachment({name:file.name,type:file.type,data:r.result,date:new Date().toISOString()});a?res(a):rej(new Error('Invalid attachment'))};r.onerror=rej;r.readAsDataURL(file)})}
function showAttachment(kind){const box=document.getElementById(kind+'AttachmentInfo'),a=safeAttachment(pendingAttachment[kind]);pendingAttachment[kind]=a;box.classList.toggle('hidden',!a);box.replaceChildren();if(a){box.append(document.createTextNode(`📎 ${a.name} `));const button=document.createElement('button');button.type='button';button.className='ghost small';button.textContent='Remove';button.onclick=()=>{pendingAttachment[kind]=null;showAttachment(kind)};box.append(button)}}
function vehicleDistance(v){return state.trips.filter(t=>t.vehicleId===v.id).reduce((sum,t)=>sum+Number(t.km||0),0)}
function calculatedOdometer(v){const logged=vehicleDistance(v),base=Number(v.odometerBase??v.currentOdometer??v.initialOdometer??0),baseline=Number(v.odometerBaselineTripKm||0);return Math.max(0,base+(logged-baseline))}
function addMonthsISO(date,months){const d=new Date((date||todayISO())+'T12:00:00');if(Number.isNaN(d.getTime()))return '';d.setMonth(d.getMonth()+Number(months||0));return d.toISOString().slice(0,10)}
function maintenanceTimeline(v){
  const base=Number(v.odometerBase??v.currentOdometer??v.initialOdometer??0);
  const odometerLogs=state.expenses.filter(e=>e.vehicleId===v.id&&Number(e.odometer||0)>0);
  const current=Math.max(calculatedOdometer(v),...odometerLogs.map(e=>Number(e.odometer||0)),base,0);
  const maintenance=state.expenses.filter(e=>e.vehicleId===v.id&&e.category==='Maintenance').sort((a,b)=>String(a.date||'').localeCompare(String(b.date||'')));
  const last=maintenance.at(-1),intervalKm=Number(v.maintenanceKm||0),intervalMonths=Number(v.maintenanceMonths||0);
  const lastDate=v.lastMaintenanceDate||last?.date||'',lastOdo=Number(v.lastMaintenanceOdometer||last?.odometer||0)||0;
  const automaticDueKm=(lastOdo&&intervalKm)?lastOdo+intervalKm:0,automaticDueDate=(lastDate&&intervalMonths)?addMonthsISO(lastDate,intervalMonths):'';
  const dueKm=Number(v.nextMaintenanceKm||0)||automaticDueKm,dueDate=v.nextMaintenanceDate||automaticDueDate;
  const dueDateLabel=dueDate?new Date(dueDate+'T12:00:00').toLocaleDateString(window.MOBUD_I18N?.locale?.()||undefined):'';
  const parts=[];if(dueDateLabel)parts.push(`${t('on')} ${dueDateLabel}`);if(dueKm)parts.push(`${t('at')} ${dueKm.toLocaleString(window.MOBUD_I18N?.locale?.()||undefined)} km`);
  const due=parts.length?`${t('Next maintenance')} ${parts.join(` ${t('or')} `)}`:t('No maintenance interval configured');
  const overdue=(dueDate&&dueDate<todayISO())||(dueKm&&current>=dueKm);
  return `<div class="maintenance-summary ${overdue?'maintenance-overdue':''}"><span>${escapeHtml(due)}</span><small>${t('Current odometer')}: ${current.toLocaleString(window.MOBUD_I18N?.locale?.()||undefined,{maximumFractionDigits:1})} km</small>${lastDate?`<small>${t('Last maintenance')}: ${escapeHtml(lastDate)}${lastOdo?` · ${lastOdo.toLocaleString()} km`:''}</small>`:''}</div>`
}
function syncGarageFilterOptions(){const typeSelect=document.getElementById('garageTypeFilter'),powerSelect=document.getElementById('garagePowertrainFilter');if(!typeSelect||!powerSelect)return;const active=state.vehicles.filter(v=>v.active!==false),types=[...new Set(active.map(v=>v.type).filter(Boolean))],powers=[...new Set(active.map(v=>v.powertrain||'not_applicable').filter(Boolean))],currentType=typeSelect.value||'all',currentPower=powerSelect.value||'all';typeSelect.innerHTML=`<option value="all">${t('All vehicle types')}</option>`+types.map(value=>`<option value="${safeAttr(value)}">${escapeHtml(vehicleTypeLabel(value))}</option>`).join('');powerSelect.innerHTML=`<option value="all">${t('All powertrains')}</option>`+powers.map(value=>`<option value="${safeAttr(value)}">${escapeHtml(powertrainLabel(value))}</option>`).join('');typeSelect.value=types.includes(currentType)?currentType:'all';powerSelect.value=powers.includes(currentPower)?currentPower:'all'}

