function mailLink(label,emailLike,v,kind){const to=String(emailLike||'').includes('@')?String(emailLike).trim():'';const subject=encodeURIComponent(`${t('Vehicle question')} - ${v.name||''}`);const body=encodeURIComponent(`${t('Vehicle')}: ${[v.brand,v.model].filter(Boolean).join(' ')||v.name}\n${t('Display name')}: ${v.name||''}\n${t('Current odometer')}: ${calculatedOdometer(v).toFixed(1)} km\n${t('Partner')}: ${kind}\n\n${t('Description')}:\n`);return to?`<a class="secondary small" href="mailto:${safeAttr(to)}?subject=${subject}&body=${body}">${escapeHtml(label)}</a>`:''}
