  const vehicleSummary=state.vehicles.map(v=>({v,km:trips.filter(x=>x.vehicleId===v.id).reduce((s,x)=>s+Number(x.km||0),0),cost:expenses.filter(x=>x.vehicleId===v.id).reduce((s,x)=>s+Number(x.amount||0),0),count:trips.filter(x=>x.vehicleId===v.id).length,receipts:expenses.filter(x=>x.vehicleId===v.id&&x.attachment).length})).filter(x=>x.km||x.cost||x.count||x.receipts);
  root.innerHTML=`<div class="print-report-page"><div class="print-brand"><img src="icon-512-v005.png" alt="MoBud"><div><h1>${escapeHtml(t('MoBud mobility report'))}</h1><p>${escapeHtml(bounds.label)} - ${escapeHtml(bounds.from)} — ${escapeHtml(bounds.to)}</p></div></div><div class="print-kpis"><div><span>${t('Trips')}</span><strong>${trips.length}</strong></div><div><span>${t('Distance')}</span><strong>${unitDistance(totalKm)}</strong></div><div><span>${t('Costs')}</span><strong>${money(totalCost)}</strong></div><div><span>${t('Receipts')}</span><strong>${attachments.length}</strong></div></div><h2>${t('Summary per vehicle')}</h2><table><thead><tr><th>${t('Vehicle')}</th><th>${t('Trips')}</th><th>${t('Distance')}</th><th>${t('Costs')}</th><th>${t('Receipts')}</th></tr></thead><tbody>${vehicleSummary.map(x=>`<tr><td>${escapeHtml(officialVehicleName(x.v))}</td><td>${x.count}</td><td>${unitDistance(x.km)}</td><td>${money(x.cost)}</td><td>${x.receipts}</td></tr>`).join('')}</tbody></table><h2>${t('Estimated impact')}</h2><p>${t('Cycling distance')}: ${unitDistance(impact.cyclingKm)} - ${t('Public transport distance')}: ${unitDistance(impact.publicTransportKm)} - ${t('Estimated CO2 avoided')}: ${impact.estimatedCo2Saved.toFixed(1)} kg - ${t('Estimated costs saved')}: ${money(impact.cyclingCostSaved)}</p><p class="print-assumption">${t('Impact assumptions')}: ${REPORT_ASSUMPTIONS.petrolLitresPer100Km.toFixed(1)} L/100 km - €${REPORT_ASSUMPTIONS.petrolPricePerLitre.toFixed(2)}/L.</p><footer>${t('Keep it digital footer')}</footer></div>`;
  attachments.forEach((expense,index)=>{const a=safeAttachment(expense.attachment),page=document.createElement('div');page.className='print-receipt-page';const head=document.createElement('div');head.className='print-receipt-head';head.innerHTML=`<div class="print-brand mini"><img src="icon-512-v005.png" alt="MoBud"><h2>${t('Receipt')} ${index+1} ${t('of')} ${attachments.length}</h2></div><p>${escapeHtml(expense.date||'')} - ${escapeHtml(vehicleById(expense.vehicleId)?.name||t('No vehicle'))} - ${money(expense.amount||0)} - ${escapeHtml(expense.category||'')}</p>`;page.append(head);const frame=document.createElement('div');frame.className='print-receipt-frame';if(a.type==='application/pdf'){const note=document.createElement('p');note.textContent=`${t('PDF receipt')}: ${a.name}. ${t('Use PDF export to include the original PDF pages.')}`;frame.append(note)}else{const img=document.createElement('img');img.src=a.data;img.alt=a.name||t('Receipt');frame.append(img)}page.append(frame);const footer=document.createElement('footer');footer.textContent=t('Keep it digital footer');page.append(footer);root.append(page)});
  document.body.append(root);return root;
