function dataUrlBytes(dataUrl){const base64=String(dataUrl||'').split(',')[1]||'';const bin=atob(base64);const out=new Uint8Array(bin.length);for(let i=0;i<bin.length;i++)out[i]=bin.charCodeAt(i);return out}

async function imageAttachmentForPdf(pdf,a){const bytes=dataUrlBytes(a.data);if(a.type==='image/png')return pdf.embedPng(bytes);if(a.type==='image/jpeg'||a.type==='image/jpg')return pdf.embedJpg(bytes);const img=new Image();img.src=a.data;await new Promise((resolve,reject)=>{img.onload=resolve;img.onerror=reject});const canvas=document.createElement('canvas');canvas.width=img.naturalWidth||img.width;canvas.height=img.naturalHeight||img.height;const ctx=canvas.getContext('2d');ctx.drawImage(img,0,0);return pdf.embedPng(dataUrlBytes(canvas.toDataURL('image/png')))}
