function renderCalendar(){calendarTitle.textContent=fmtMonth(calendarDate);const y=calendarDate.getFullYear(),m=calendarDate.getMonth(),first=(new Date(y,m,1).getDay()+6)%7,days=new Date(y,m+1,0).getDate(),counts={};calendarRows().forEach(x=>{counts[x.date]=counts[x.date]||{total:0,trip:0,expense:0,both:0};counts[x.date].total++;if(x.kind==='trip'&&x.attachment)counts[x.date].both++;else if(x.kind==='trip')counts[x.date].trip++;else counts[x.date].expense++;});let html='';for(let i=0;i<first;i++)html+='<span></span>';for(let d=1;d<=days;d++){const iso=`${y}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;html+=`<button class="cal-day ${counts[iso]?'filled':''} ${counts[iso]?.trip?'has-trip':''} ${counts[iso]?.expense?'has-receipt':''} ${counts[iso]?.both?'has-both':''} ${iso===selectedDay?'selected':''} ${iso===todayISO()?'today':''}" data-day="${iso}"><span>${d}</span>${counts[iso]?`<small>${counts[iso].total}</small>`:''}</button>`}calendarGrid.innerHTML=html;document.querySelectorAll('[data-day]').forEach(b=>b.onclick=()=>{selectedDay=b.dataset.day;renderCalendar()});document.querySelectorAll('[data-calendar-filter]').forEach(b=>{b.classList.toggle('active',b.dataset.calendarFilter===calendarFilter);b.onclick=()=>{calendarFilter=b.dataset.calendarFilter;renderCalendar()}});selectedDayTitle.textContent=new Date(selectedDay+'T12:00:00').toLocaleDateString(undefined,{weekday:'long',day:'numeric',month:'long'});const rows=calendarRows().filter(x=>x.date===selectedDay);dayLogs.innerHTML=rows.length?rows.map(logHtml).join(''):`<div class="empty-state small"><strong>${t('No registrations on this day.')}</strong><p>${t('Use the plus button or a quick action to add a trip or receipt.')}</p></div>`;bindLogButtons(dayLogs)}
function attachmentBytes(a){if(!a?.data)return 0;const b64=String(a.data).split(',')[1]||'';return Math.round(b64.length*0.75)}
function refreshReceiptCleanupPreview(){const input=document.getElementById('receiptCleanupDate'),out=document.getElementById('receiptCleanupPreview');if(!input||!out)return;const cutoff=input.value;if(!cutoff){out.textContent=t('Choose a cutoff date to preview old receipt attachments.');return}const matches=state.expenses.filter(e=>e.attachment&&e.date&&e.date<cutoff);const bytes=matches.reduce((n,e)=>n+attachmentBytes(e.attachment),0);out.textContent=`${matches.length} ${t('receipt attachments')} · ${(bytes/1024/1024).toFixed(1)} MB`}
function cleanupOldReceiptAttachments(){const cutoff=document.getElementById('receiptCleanupDate')?.value;if(!cutoff){toast(t('Choose a cutoff date first.'));return}const matches=state.expenses.filter(e=>e.attachment&&e.date&&e.date<cutoff);if(!matches.length){toast(t('No old receipt attachments found.'));return}if(!confirm(`${t('Permanently remove')} ${matches.length} ${t('receipt attachments')} ${t('before')} ${cutoff}? ${t('Trips, costs and receipt metadata will remain.')}`))return;const now=new Date().toISOString();matches.forEach(e=>{e.attachment=null;e.attachmentRemovedAt=now;e.updatedAt=now});save();refreshReceiptCleanupPreview();toast(t('Old receipt attachments removed.'))}
